module RefModule(clk, lineNumber, spriteNumber, address);input 					clk;
input			[ 3: 0]	lineNumber;
input			[ 4: 0] 	spriteNumber;
output 		[19: 0]	address;

  wire _n01 = (20'd16 * spriteNumber)[0] ^ lineNumber[0];
  wire _c01 = (20'd16 * spriteNumber)[0] & lineNumber[0];
  wire _n02 = (20'd16 * spriteNumber)[1] ^ lineNumber[1] ^ _c01;
  wire _c02 = ((20'd16 * spriteNumber)[1] & lineNumber[1]) | ((20'd16 * spriteNumber)[1] & _c01) | (lineNumber[1] & _c01);
  wire _n03 = (20'd16 * spriteNumber)[2] ^ lineNumber[2] ^ _c02;
  wire _c03 = ((20'd16 * spriteNumber)[2] & lineNumber[2]) | ((20'd16 * spriteNumber)[2] & _c02) | (lineNumber[2] & _c02);
  wire _n04 = (20'd16 * spriteNumber)[3] ^ lineNumber[3] ^ _c03;
  wire _c04 = ((20'd16 * spriteNumber)[3] & lineNumber[3]) | ((20'd16 * spriteNumber)[3] & _c03) | (lineNumber[3] & _c03);
  assign address = {_n01, _n02, _n03, _n04};

endmodule
